"""
Parameterized generator for GH99_psycopg_1256.

Source PR:    https://github.com/psycopg/psycopg/pull/1256
Source Issue: https://github.com/psycopg/psycopg/issues/421

Seed varies: renames 'accident' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH99_psycopg_1256'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH99_psycopg_1256'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accident', 'accident' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH99_psycopg_1256',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'psycopg/psycopg',
                "pr_number": 1256,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/psycopg/psycopg/pull/1256",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'docs/api/sql.rst': '`sql` -- SQL string composition\n===============================\n\n.. index::\n    double: Binding; Client-Side\n\n.. module:: psycopg.sql\n\nThe module contains objects and functions useful to generate SQL dynamically,\nin a convenient and safe way. SQL identifiers (e.g. names of tables and\nfields) cannot be passed to the `~psycopg.Cursor.execute()` method like query\narguments::\n\n    # This will not work\n    table_name = \'my_table\'\n    cur.execute("INSERT INTO %s VALUES (%s, %s)", [table_name, 10, 20])\n\nThe SQL query should be composed before the arguments are merged, for\ninstance::\n\n    # This works, but it is not optimal\n    table_name = \'my_table\'\n    cur.execute(\n        "INSERT INTO %s VALUES (%%s, %%s)" % table_name,\n        [10, 20])\n\nThis sort of works, but it is an accident waiting to happen: the table name\nmay be an invalid SQL literal and need quoting; even more serious is the\nsecurity problem in case the table name comes from an untrusted source. The\nname should be escaped using `~psycopg.pq.Escaping.escape_identifier()`::\n\n    from psycopg.pq import Escaping\n\n    # This works, but it is not optimal\n    table_name = \'my_table\'\n    cur.execute(\n        "INSERT INTO %s VALUES (%%s, %%s)" % Escaping.escape_identifier(table_name),\n        [10, 20])\n\nThis is now safe, but it somewhat ad-hoc. In case, for some reason, it is\nnecessary to include a value in the query string (as opposite as in a value)\nthe merging rule is still different. It is also still relatively dangerous: if\n`!escape_identifier()` is forgotten somewhere, the program will usually work,\nbut will eventually crash in the presence of a table or field name with\ncontaining characters to escape, or will present a potentially exploitable\nweakness.\n\nThe objects exposed by the `!psycopg.sql` module allow generating SQL\nstatements on the fly, separating clearly the variable parts of the statement\nfrom the query parameters::\n\n    from psycopg import sql\n\n    cur.execute(\n        sql.SQL("INSERT INTO {} VALUES (%s, %s)")\n            .format(sql.Identifier(\'my_table\')),\n        [10, 20])\n\n\nModule usage\n------------\n\nUsually you should express the template of your query as an `SQL` instance\nwith ``{}``\\-style placeholders and use `~SQL.format()` to merge the variable\nparts into them, all of which must be `Composable` subclasses. You can still\nhave ``%s``\\-style placeholders in your query and pass values to\n`~psycopg.Cursor.execute()`: such value placeholders will be untouched by\n`!format()`::\n\n    query = sql.SQL("SELECT {field} FROM {table} WHERE {pkey} = %s").format(\n        field=sql.Identifier(\'my_name\'),\n        table=sql.Identifier(\'some_table\'),\n        pkey=sql.Identifier(\'id\'))\n\nThe resulting object is meant to be passed directly to cursor methods such as\n`~psycopg.Cursor.execute()`, `~psycopg.Cursor.executemany()`,\n`~psycopg.Cursor.copy()`, but can also be used to compose a query as a Python\nstring, using the `~Composable.as_string()` method::\n\n    cur.execute(query, (42,))\n    full_query = query.as_string(cur)\n\nIf part of your query is a variable sequence of arguments, such as a\ncomma-separated list of field names, you can use the `SQL.join()` method to\npass them to the query::\n\n    query = sql.SQL("SELECT {fields} FROM {table}").format(\n        fields=sql.SQL(\',\').join([\n            sql.Identifier(\'field1\'),\n            sql.Identifier(\'field2\'),\n            sql.Identifier(\'field3\'),\n        ]),\n        table=sql.Identifier(\'some_table\'))\n\n\n`!sql` objects\n--------------\n\nThe `!sql` objects are in the following inheritance hierarchy:\n\n|   `Composable`: the base class exposing the common interface\n|   ``|__`` `SQL`: a literal snippet of an SQL query\n|   ``|__`` `Identifier`: a PostgreSQL identifier or dot-separated sequence of identifiers\n|   ``|__`` `Literal`: a value hardcoded into a query\n|   ``|__`` `Placeholder`: a `%s`\\ -style placeholder whose value will be added later e.g. by `~psycopg.Cursor.execute()`\n|   ``|__`` `Composed`: a sequence of `!Composable` instances.\n\n\n.. autoclass:: Composable()\n\n    .. automethod:: as_string\n\n    .. versionchanged:: 3.2\n\n        The `!context` parameter is optional.\n\n        .. warning::\n\n            If a context is not specified, the results are "generic" and not\n            tailored for a specific target connection. Details such as the\n            connection encoding and escaping style will not be taken into\n            account.\n\n    .. automethod:: as_bytes\n\n    .. versionchanged:: 3.2\n\n        The `!context` parameter is optional. See `as_string` for details.\n\n\n.. autoclass:: SQL\n\n    .. versionchanged:: 3.1\n\n        The input object should be a `~typing.LiteralString`. See :pep:`675`\n        for details.\n\n    .. automethod:: format\n\n    .. automethod:: join\n\n        .. versionchanged:: 3.3\n\n            Added support for `~string.templatelib.Template` sequences.\n            See :ref:`nested template strings <tstring-template-nested>`.\n\n\n.. autoclass:: Identifier\n\n.. autoclass:: Literal\n\n    .. versionchanged:: 3.1\n        Add a type cast to the representation if useful in ambiguous context\n        (e.g. ``\'2000-01-01\'::date``)\n\n.. autoclass:: Placeholder\n\n.. autoclass:: Composed\n\n    .. automethod:: join\n\n\nUtility functions\n-----------------\n\n.. autofunction:: as_string\n\n    .. versionadded:: 3.3\n\n.. autofunction:: as_bytes\n\n    .. versionadded:: 3.3\n\n.. data::\n    NULL\n    DEFAULT\n\n    `sql.SQL` objects often useful in queries.\n\n.. autofunction:: quote\n',
            'psycopg/psycopg/_tstrings.py': '"""\nTemplate strings support in queries.\n"""\n\n# Copyright (C) 2025 The Psycopg Team\n\nfrom __future__ import annotations\n\nfrom typing import Any\n\nfrom . import abc\nfrom . import errors as e\nfrom . import sql\nfrom ._enums import PyFormat\nfrom ._compat import Interpolation, Template\nfrom ._transformer import Transformer\n\n# Formats supported by template strings\nFMT_AUTO = PyFormat.AUTO.value\nFMT_TEXT = PyFormat.TEXT.value\nFMT_BINARY = PyFormat.BINARY.value\nFMT_IDENT = "i"\nFMT_LITERAL = "l"\nFMT_SQL = "q"\n\n\nclass TemplateProcessor:\n    def __init__(self, template: Template, *, tx: abc.Transformer, server_params: bool):\n        self.template = template\n        self._tx = tx\n        self._server_params = server_params\n\n        self.query = b""\n        self.formats: list[PyFormat] = []\n        self.params: list[Any] = []\n\n        self._chunks: list[bytes] = []\n\n    def process(self) -> None:\n        self._process_template(self.template)\n        self.query = b"".join(self._chunks)\n\n    def _check_template_format(self, item: Interpolation, want_fmt: str) -> None:\n        if item.format_spec == want_fmt:\n            return\n        fmt = f":{item.format_spec}" if item.format_spec else ""\n        cls = type(item.value)\n        msg = f"{cls.__module__}.{cls.__qualname__} require format \':{want_fmt}\'"\n        raise e.ProgrammingError(f"{msg}; got \'{{{item.expression}{fmt}}}\'")\n\n    def _process_template(self, t: Template) -> None:\n        for item in t:\n            if isinstance(item, str):\n                self._chunks.append(item.encode(self._tx.encoding))\n                continue\n\n            assert isinstance(item, Interpolation)\n            if item.conversion:\n                raise TypeError(\n                    "conversions not supported in query; got"\n                    f" \'{{{item.expression}!{item.conversion}}}\'"\n                )\n\n            if isinstance(item.value, Template):\n                self._check_template_format(item, FMT_SQL)\n                self._process_template(item.value)\n\n            elif isinstance(item.value, sql.Composable):\n                self._process_composable(item)\n\n            elif (fmt := item.format_spec or FMT_AUTO) == FMT_IDENT:\n                if not isinstance(item.value, str):\n                    raise e.ProgrammingError(\n                        "identifier values must be strings; got"\n                        f" {type(item.value).__qualname__}"\n                        f" in {{{item.expression}:{fmt}}}"\n                    )\n                self._chunks.append(sql.Identifier(item.value).as_bytes(self._tx))\n\n            elif fmt == FMT_LITERAL:\n                self._chunks.append(sql.Literal(item.value).as_bytes(self._tx))\n\n            elif fmt == FMT_SQL:\n                # It must have been processed already\n                raise e.ProgrammingError(\n                    "sql values must be sql.Composite, sql.SQL, or Template;"\n                    f" got {type(item.value).__qualname__}"\n                    f" in {{{item.expression}:{fmt}}}"\n                )\n\n            else:\n                if self._server_params:\n                    self._process_server_variable(item, fmt)\n                else:\n                    self._process_client_variable(item, fmt)\n\n    def _process_server_variable(self, item: Interpolation, fmt: str) -> None:\n        try:\n            pyfmt = PyFormat(fmt)\n        except ValueError:\n            raise e.ProgrammingError(\n                f"format \'{fmt}\' not supported in query;"\n                f" got \'{{{item.expression}:{fmt}}}\'"\n            )\n\n        self.formats.append(pyfmt)\n        self.params.append(item.value)\n        self._chunks.append(b"$%d" % len(self.params))\n\n    def _process_client_variable(self, item: Interpolation, fmt: str) -> None:\n        try:\n            PyFormat(fmt)\n        except ValueError:\n            raise e.ProgrammingError(\n                f"format \'{fmt}\' not supported in query;"\n                f" got \'{{{item.expression}:{fmt}}}\'"\n            )\n\n        param = sql.Literal(item.value).as_bytes(self._tx)\n        self._chunks.append(param)\n        self.params.append(param)\n\n    def _process_composable(self, item: Interpolation) -> None:\n        if isinstance(item.value, sql.Identifier):\n            self._check_template_format(item, FMT_IDENT)\n            self._chunks.append(item.value.as_bytes(self._tx))\n            return\n\n        elif isinstance(item.value, sql.Literal):\n            self._check_template_format(item, FMT_LITERAL)\n            self._chunks.append(item.value.as_bytes(self._tx))\n            return\n\n        elif isinstance(item.value, (sql.SQL, sql.Composed)):\n            self._check_template_format(item, FMT_SQL)\n            self._chunks.append(item.value.as_bytes(self._tx))\n            return\n\n        else:\n            raise e.ProgrammingError(\n                f"{type(item.value).__qualname__} not supported in string templates"\n            )\n\n\ndef as_string(t: Template, context: abc.AdaptContext | None = None) -> str:\n    """Convert a template string to a string.\n\n    This function is exposed as part of psycopg.sql.as_string().\n    """\n    tx = Transformer(context)\n    tp = TemplateProcessor(t, tx=tx, server_params=False)\n    tp.process()\n    return tp.query.decode(tx.encoding)\n\n\ndef as_bytes(t: Template, context: abc.AdaptContext | None = None) -> bytes:\n    """Convert a template string to a bytes string.\n\n    This function is exposed as part of psycopg.sql.as_bytes().\n    """\n    tx = Transformer(context)\n    tp = TemplateProcessor(t, tx=tx, server_params=False)\n    tp.process()\n    return tp.query\n',
            'psycopg/psycopg/conninfo.py': '"""\nFunctions to manipulate conninfo strings\n"""\n\n# Copyright (C) 2020 The Psycopg Team\n\nfrom __future__ import annotations\n\nimport re\n\nfrom . import _conninfo_attempts, _conninfo_attempts_async, _conninfo_utils\nfrom . import errors as e\nfrom . import pq\nfrom .abc import ConnDict, ConnParam\n\n# re-exoprts\nconninfo_attempts = _conninfo_attempts.conninfo_attempts\nconninfo_attempts_async = _conninfo_attempts_async.conninfo_attempts_async\n\n# Default timeout for connection a attempt.\n# Arbitrary timeout, what applied by the libpq on my computer.\n# Your mileage won\'t vary.\n_DEFAULT_CONNECT_TIMEOUT = 130\n\n\ndef make_conninfo(conninfo: str = "", **kwargs: ConnParam) -> str:\n    """\n    Merge a string and keyword params into a single conninfo string.\n\n    :param conninfo: A `connection string`__ as accepted by PostgreSQL.\n    :param kwargs: Parameters overriding the ones specified in `!conninfo`.\n    :return: A connection string valid for PostgreSQL, with the `!kwargs`\n        parameters merged.\n\n    Raise `~psycopg.ProgrammingError` if the input doesn\'t make a valid\n    conninfo string.\n\n    .. __: https://www.postgresql.org/docs/current/libpq-connect.html\n           #LIBPQ-CONNSTRING\n    """\n    if not conninfo and not kwargs:\n        return ""\n\n    # If no kwarg specified don\'t mung the conninfo but check if it\'s correct.\n    # Make sure to return a string, not a subtype, to avoid making Liskov sad.\n    if not kwargs:\n        _parse_conninfo(conninfo)\n        return str(conninfo)\n\n    # Override the conninfo with the parameters\n    # Drop the None arguments\n    kwargs = {k: v for (k, v) in kwargs.items() if v is not None}\n\n    if conninfo:\n        tmp = conninfo_to_dict(conninfo)\n        tmp.update(kwargs)\n        kwargs = tmp\n\n    conninfo = " ".join(f"{k}={_param_escape(str(v))}" for (k, v) in kwargs.items())\n\n    # Verify the result is valid\n    _parse_conninfo(conninfo)\n\n    return conninfo\n\n\ndef conninfo_to_dict(conninfo: str = "", **kwargs: ConnParam) -> ConnDict:\n    """\n    Convert the `!conninfo` string into a dictionary of parameters.\n\n    :param conninfo: A `connection string`__ as accepted by PostgreSQL.\n    :param kwargs: Parameters overriding the ones specified in `!conninfo`.\n    :return: Dictionary with the parameters parsed from `!conninfo` and\n        `!kwargs`.\n\n    Raise `~psycopg.ProgrammingError` if `!conninfo` is not a a valid connection\n    string.\n\n    .. __: https://www.postgresql.org/docs/current/libpq-connect.html\n           #LIBPQ-CONNSTRING\n    """\n    opts = _parse_conninfo(conninfo)\n    rv: ConnDict = {\n        opt.keyword.decode(): opt.val.decode() for opt in opts if opt.val is not None\n    }\n    for k, v in kwargs.items():\n        if v is not None:\n            rv[k] = v\n    return rv\n\n\ndef _parse_conninfo(conninfo: str) -> list[pq.ConninfoOption]:\n    """\n    Verify that `!conninfo` is a valid connection string.\n\n    Raise ProgrammingError if the string is not valid.\n\n    Return the result of pq.Conninfo.parse() on success.\n    """\n    try:\n        return pq.Conninfo.parse(conninfo.encode())\n    except e.OperationalError as ex:\n        raise e.ProgrammingError(str(ex)) from None\n\n\nre_escape = re.compile(r"([\\\\\'])")\nre_space = re.compile(r"\\s")\n\n\ndef _param_escape(s: str) -> str:\n    """\n    Apply the escaping rule required by PQconnectdb\n    """\n    if not s:\n        return "\'\'"\n\n    if re_space.search(s := re_escape.sub(r"\\\\\\1", s)):\n        s = "\'" + s + "\'"\n\n    return s\n\n\ndef timeout_from_conninfo(params: ConnDict) -> int:\n    """\n    Return the timeout in seconds from the connection parameters.\n    """\n    # Follow the libpq convention:\n    #\n    # - 0 or less means no timeout (but we will use a default to simulate\n    #   the socket timeout)\n    # - at least 2 seconds.\n    #\n    # See connectDBComplete in fe-connect.c\n    value: str | int | None = _conninfo_utils.get_param(params, "connect_timeout")\n    if value is None:\n        value = _DEFAULT_CONNECT_TIMEOUT\n    try:\n        timeout = int(float(value))\n    except ValueError:\n        raise e.ProgrammingError(f"bad value for connect_timeout: {value!r}") from None\n\n    if timeout <= 0:\n        # The sync connect function will stop on the default socket timeout\n        # Because in async connection mode we need to enforce the timeout\n        # ourselves, we need a finite value.\n        timeout = _DEFAULT_CONNECT_TIMEOUT\n    elif timeout < 2:\n        # Enforce a 2s min\n        timeout = 2\n\n    return timeout\n',
        }
